import { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { resolveUrl } from '../utils';
import { Button } from 'primereact/button';
import { InputText } from 'primereact/inputtext';
import { InputNumber } from 'primereact/inputnumber';
import { ProgressSpinner } from 'primereact/progressspinner';
import { confirmDialog } from 'primereact/confirmdialog';
import { FileUpload } from 'primereact/fileupload';
import { Rating } from 'primereact/rating';
import { Dialog } from 'primereact/dialog';
import ItemDetailDialog from './ItemDetailDialog';
import GiftCard from './GiftCard';

const API_BASE = 'http://localhost:8081/api/v1';

function ItemsDialog({ wishlist, visible, onHide, toast, readOnly = false, onItemsChanged, user, breadcrumb }) {
  const canAdd = !readOnly;
  
  // Определяем является ли текущий пользователь владельцем вишлиста
  const currentUserId = user?.id;
  const isOwner = currentUserId && wishlist.userId && currentUserId === wishlist.userId;
  
  console.log('ItemsDialog DEBUG:', { 
    currentUserId, 
    wishlistUserId: wishlist.userId,
    user: user,
    isOwner 
  });

  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [uploadLoading, setUploadLoading] = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [itemSort, setItemSort] = useState('createdAt_desc');
  const fileUploadRef = useRef(null);
  const [itemMenuOpen, setItemMenuOpen] = useState(null);
  const [editingItem, setEditingItem] = useState(null);
  const [showMoveDialog, setShowMoveDialog] = useState(false);
  const [movingItem, setMovingItem] = useState(null);
  const [userWishlists, setUserWishlists] = useState([]);

  const sortItems = (list) => {
    const sorted = [...list];
    switch (itemSort) {
      case 'title_asc': return sorted.sort((a, b) => a.title.localeCompare(b.title, 'ru'));
      case 'title_desc': return sorted.sort((a, b) => b.title.localeCompare(a.title, 'ru'));
      case 'price_asc': return sorted.sort((a, b) => (a.price ?? 0) - (b.price ?? 0));
      case 'price_desc': return sorted.sort((a, b) => (b.price ?? 0) - (a.price ?? 0));
      case 'priority_desc': return sorted.sort((a, b) => b.priority - a.priority);
      case 'createdAt_desc': default: return sorted.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
    }
  };
  const [formData, setFormData] = useState({ title: '', url: '', imageUrl: '', price: null, priority: 5, description: '' });

  useEffect(() => {
    if (visible) loadItems();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [visible, wishlist.id]);
  
  if (!visible) return null;

  const getAuthHeaders = () => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: `Bearer ${token}` } : {};
  };

  const loadItems = async () => {
    try {
      setLoading(true);
      const r = await axios.get(`${API_BASE}/wishlists/${wishlist.id}/items?page=1&per_page=100`, {
        headers: getAuthHeaders()
      });
      setItems(r.data.items || []);
    } catch {
      toast.current?.show({ severity: 'error', summary: 'Ошибка загрузки', life: 3000 });
    } finally {
      setLoading(false);
    }
  };

  const handleAddItem = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API_BASE}/wishlists/${wishlist.id}/items`, 
        { ...formData, wishlistId: wishlist.id },
        { headers: getAuthHeaders() }
      );
      setFormData({ title: '', url: '', imageUrl: '', price: null, priority: 5, description: '' });
      setShowAddForm(false);
      loadItems();
      toast.current?.show({ severity: 'success', summary: 'Элемент добавлен', life: 3000 });
      
      // Обновляем список вишлистов в родительском компоненте
      if (onItemsChanged) {
        onItemsChanged();
      }
    } catch {
      toast.current?.show({ severity: 'error', summary: 'Ошибка', life: 3000 });
    }
  };

  const handleImageUpload = async (event) => {
    const file = event.files[0];
    if (!file) return;
    console.log('ItemsDialog: Загружаем файл:', file.name, file.size, file.type);
    setUploadLoading(true);
    const fd = new FormData();
    fd.append('file', file);
    try {
      console.log('ItemsDialog: Отправляем на сервер...');
      const r = await axios.post(`${API_BASE}/upload/image`, fd, { 
        headers: { 
          'Content-Type': 'multipart/form-data',
          ...getAuthHeaders()
        } 
      });
      console.log('ItemsDialog: Файл загружен:', r.data);
      setFormData(prev => ({ ...prev, imageUrl: r.data.url }));
      if (fileUploadRef.current) fileUploadRef.current.clear();
      toast.current?.show({ severity: 'success', summary: 'Фото загружено', life: 3000 });
    } catch (error) {
      console.error('ItemsDialog: Ошибка загрузки фото:', error);
      toast.current?.show({ severity: 'error', summary: 'Ошибка загрузки фото', life: 3000 });
    } finally {
      setUploadLoading(false);
    }
  };

  const handleTogglePurchased = async (item) => {
    try {
      await axios.patch(`${API_BASE}/wishlists/${wishlist.id}/items/${item.id}`, 
        { isPurchased: !item.isPurchased },
        { headers: getAuthHeaders() }
      );
      loadItems();
    } catch {}
  };

  const handleReserve = async (item, isIncognito = false) => {
    try {
      const headers = getAuthHeaders();
      console.log('Reserve headers:', headers);
      await axios.post(`${API_BASE}/wishlists/${wishlist.id}/items/${item.id}/reserve`, 
        { isIncognito },
        { headers }
      );
      loadItems();
      toast.current?.show({ severity: 'success', summary: isIncognito ? 'Забронировано инкогнито' : 'Забронировано', life: 3000 });
    } catch (error) {
      console.error('Reserve error:', error.response?.data || error.message);
      toast.current?.show({ severity: 'error', summary: 'Ошибка бронирования', life: 3000 });
    }
  };

  const handleUnreserve = async (item) => {
    try {
      await axios.delete(`${API_BASE}/wishlists/${wishlist.id}/items/${item.id}/reserve`, {
        headers: getAuthHeaders()
      });
      loadItems();
      toast.current?.show({ severity: 'success', summary: 'Бронирование снято', life: 3000 });
    } catch (error) {
      toast.current?.show({ severity: 'error', summary: 'Ошибка', life: 3000 });
    }
  };

  const handleDeleteItem = (itemId) => {
    confirmDialog({
      message: 'Удалить этот элемент?',
      header: 'Подтверждение',
      acceptLabel: 'Да',
      rejectLabel: 'Нет',
      accept: async () => {
        try {
          await axios.delete(`${API_BASE}/wishlists/${wishlist.id}/items/${itemId}`, {
            headers: getAuthHeaders()
          });
          loadItems();
          
          // Обновляем список вишлистов в родительском компоненте
          if (onItemsChanged) {
            onItemsChanged();
          }
        } catch {}
      }
    });
  };


  const handleMoveItem = async (item, targetWishlistId) => {
    try {
      await axios.patch(`${API_BASE}/wishlists/${wishlist.id}/items/${item.id}`,
        { wishlistId: targetWishlistId },
        { headers: getAuthHeaders() }
      );
      setShowMoveDialog(false);
      setMovingItem(null);
      loadItems();
      if (onItemsChanged) onItemsChanged();
      toast.current?.show({ severity: 'success', summary: 'Подарок перенесён', life: 3000 });
    } catch {
      toast.current?.show({ severity: 'error', summary: 'Ошибка переноса', life: 3000 });
    }
  };

  const openMoveDialog = async (item) => {
    setMovingItem(item);
    setItemMenuOpen(null);
    try {
      const r = await axios.get(`${API_BASE}/wishlists?user_id=${user?.id}&page=1&per_page=50`);
      setUserWishlists((r.data.items || []).filter(w => w.id !== wishlist.id));
    } catch {}
    setShowMoveDialog(true);
  };

  const handleEditItem = (item) => {
    setEditingItem(item);
    setFormData({
      title: item.title || '',
      url: item.url || '',
      imageUrl: item.imageUrl || '',
      price: item.price || null,
      priority: item.priority || 5,
      description: item.description || '',
    });
    setItemMenuOpen(null);
    setShowAddForm(true);
  };

  const handleUpdateItem = async (e) => {
    e.preventDefault();
    try {
      await axios.patch(`${API_BASE}/wishlists/${wishlist.id}/items/${editingItem.id}`,
        formData,
        { headers: getAuthHeaders() }
      );
      setFormData({ title: '', url: '', imageUrl: '', price: null, priority: 5, description: '' });
      setEditingItem(null);
      setShowAddForm(false);
      loadItems();
      toast.current?.show({ severity: 'success', summary: 'Подарок обновлён', life: 3000 });
    } catch {
      toast.current?.show({ severity: 'error', summary: 'Ошибка', life: 3000 });
    }
  };

  return (
    <div className="items-page-container">
      {showAddForm ? (
        <>
          {/* Хлебные крошки для формы добавления */}
          <div className="breadcrumbs">
            <i className="pi pi-home" onClick={onHide}></i>
            <i className="pi pi-angle-right"></i>
            <span className="clickable" onClick={onHide}>{breadcrumb || 'Мои вишлисты'}</span>
            <i className="pi pi-angle-right"></i>
            <span className="clickable" onClick={() => { setShowAddForm(false); setEditingItem(null); }}>{wishlist.title || wishlist.name}</span>
            <i className="pi pi-angle-right"></i>
            <span>Добавить подарок</span>
          </div>

          {/* Заголовок */}
          <h2 style={{ fontStyle: 'normal', fontSize: '24.5px', fontWeight: 600, marginBottom: '1.5rem', marginTop: '1.5rem' }}>
            {editingItem ? 'Редактировать подарок:' : 'Добавить подарок:'}
          </h2>

          {/* Форма добавления подарка */}
          <div className="items-dialog-container">
            <form onSubmit={editingItem ? handleUpdateItem : handleAddItem}>
              <div className="flex flex-column gap-3">
                <div>
                  <label style={{ display: 'block', marginBottom: '8px', fontSize: '14px' }}>Название подарка *</label>
                  <InputText 
                    value={formData.title} 
                    onChange={e => setFormData({ ...formData, title: e.target.value })} 
                    placeholder="Введите название" 
                    required 
                    className="w-full" 
                  />
                </div>
                
                <div>
                  <label style={{ display: 'block', marginBottom: '8px', fontSize: '14px' }}>Ссылка на товар</label>
                  <InputText 
                    value={formData.url} 
                    onChange={e => setFormData({ ...formData, url: e.target.value })} 
                    placeholder="https://..." 
                    className="w-full" 
                  />
                </div>
                
                <div>
                  <label style={{ display: 'block', marginBottom: '8px', fontSize: '14px' }}>Цена (₽)</label>
                  <InputNumber 
                    value={formData.price} 
                    onValueChange={e => setFormData({ ...formData, price: e.value })} 
                    placeholder="0" 
                    className="w-full" 
                    minFractionDigits={0} 
                  />
                </div>
                
                <div>
                  <label style={{ display: 'block', marginBottom: '8px', fontSize: '14px' }}>Приоритет (важность)</label>
                  <Rating 
                    value={formData.priority} 
                    onChange={e => setFormData({ ...formData, priority: e.value })} 
                    cancel={false}
                    onIcon={<img src="/images/path-2.svg" alt="heart" width="20px" height="20px" />}
                    offIcon={<img src="/images/ti-heart.svg" alt="heart" width="20px" height="20px" />}
                  />
                </div>
                
                <div>
                  <label style={{ display: 'block', marginBottom: '8px', fontSize: '14px' }}>Комментарий</label>
                  <textarea
                    value={formData.description}
                    onChange={e => setFormData({ ...formData, description: e.target.value })}
                    placeholder="Добавьте комментарий к подарку"
                    rows={3}
                    className="p-inputtextarea p-inputtext p-component"
                    style={{ width: '100%' }}
                  />
                </div>
                
                <div>
                  <label style={{ display: 'block', marginBottom: '8px', fontSize: '14px' }}>Изображение подарка</label>
                  <FileUpload 
                    ref={fileUploadRef} 
                    mode="basic" 
                    name="file" 
                    accept="image/*" 
                    maxFileSize={5000000} 
                    onSelect={handleImageUpload} 
                    chooseLabel="Выбрать фото" 
                    disabled={uploadLoading}
                    auto
                    customUpload
                    uploadHandler={handleImageUpload}
                    chooseOptions={{
                      className: 'image-upload-area-button',
                      style: { display: 'none' }
                    }}
                  />
                  <div 
                    className="image-upload-area"
                    onClick={() => fileUploadRef.current?.getInput()?.click()}
                    style={{ cursor: 'pointer' }}
                  >
                    <i className="pi pi-upload" style={{ fontSize: '32px', color: '#666' }}></i>
                    <p style={{ margin: '8px 0 0 0', fontSize: '14px', color: '#666' }}>
                      Чтобы загрузить файлы кликните или перетащите их в эту область
                    </p>
                    <p style={{ margin: '4px 0 0 0', fontSize: '12px', color: '#999' }}>
                      Можно загрузить не более 1 файла
                    </p>
                  </div>
                  {formData.imageUrl && (
                    <div style={{ marginTop: '12px', position: 'relative', display: 'inline-block' }}>
                      <img 
                        src={resolveUrl(formData.imageUrl)} 
                        alt="preview" 
                        style={{ width: '120px', height: '120px', objectFit: 'cover', borderRadius: '8px' }} 
                      />
                      <button
                        type="button"
                        onClick={() => setFormData({ ...formData, imageUrl: '' })}
                        style={{
                          position: 'absolute',
                          top: '-8px',
                          right: '-8px',
                          background: '#ff4444',
                          color: 'white',
                          border: 'none',
                          borderRadius: '50%',
                          width: '24px',
                          height: '24px',
                          cursor: 'pointer',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center'
                        }}
                      >
                        ×
                      </button>
                    </div>
                  )}
                </div>
                
                <Button 
                  type="submit" 
                  label="Сохранить" 
                  icon="pi pi-check" 
                  disabled={uploadLoading}
                  className="save-gift-button"
                  style={{ marginTop: '12px' }}
                />
              </div>
            </form>
          </div>
        </>
      ) : (
        <>
          {/* Хлебные крошки для списка подарков */}
          <div className="breadcrumbs">
            <i className="pi pi-home" onClick={onHide}></i>
            <i className="pi pi-angle-right"></i>
            <span className="clickable" onClick={onHide}>{breadcrumb || 'Мои вишлисты'}</span>
            <i className="pi pi-angle-right"></i>
            <span>{wishlist.title || wishlist.name}</span>
          </div>

          {/* Заголовок с кнопкой добавить */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '0.5rem', marginBottom: '1.5rem' }}>
            <div>
              <h2 style={{ fontStyle: 'normal', fontSize: '24.5px', fontWeight: 600, margin: 0 }}>
                {wishlist.title || wishlist.name}
              </h2>
              {wishlist.description && (
                <p style={{ 
                  fontSize: '16px', 
                  fontWeight: '400', 
                  color: '#64748b', 
                  margin: '8px 0 0 0' 
                }}>
                  {wishlist.description}
                </p>
              )}
            </div>
            {canAdd && items.length > 0 && (
              <Button
                label="Добавить подарок"
                icon="pi pi-plus"
                onClick={() => setShowAddForm(true)}
                className="custom-green-button"
              />
            )}
          </div>

          {/* Список подарков */}
          {loading ? (
            <div className="flex justify-content-center p-4"><ProgressSpinner /></div>
          ) : items.length === 0 ? (
            <div style={{
              width: '945px',
              height: '482px',
              background: '#FFFFFF',
              borderRadius: '14px',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'flex-end',
              padding: '40px 40px 30px 40px',
              margin: '0 auto',
              gap: '16px',
              position: 'relative',
              overflow: 'hidden'
            }}>
              {/* Звездочки */}
              <img src="/images/zv1.svg" alt="" style={{ position: 'absolute', top: '30px', left: '80px', width: '100px', height: '100px' }} />
              <img src="/images/zv2.svg" alt="" style={{ position: 'absolute', top: '120px', left: '230px', width: '80px', height: '80px' }} />
              <img src="/images/zv3.svg" alt="" style={{ position: 'absolute', top: '200px', left: '50px', width: '90px', height: '90px' }} />
              <img src="/images/zv4.svg" alt="" style={{ position: 'absolute', top: '340px', left: '120px', width: '100px', height: '100px' }} />
              <img src="/images/zv5.svg" alt="" style={{ position: 'absolute', top: '50px', right: '200px', width: '110px', height: '110px' }} />
              <img src="/images/zv6.svg" alt="" style={{ position: 'absolute', top: '130px', right: '80px', width: '100px', height: '100px' }} />
              <img src="/images/zv7.svg" alt="" style={{ position: 'absolute', top: '280px', right: '150px', width: '90px', height: '90px' }} />
              
              {/* Персонаж */}
              <img src="/images/us.svg" alt="Персонаж" style={{ position: 'absolute', top: '50px', left: '50%', transform: 'translateX(-50%)', width: '240px', height: 'auto' }} />
              
              <div style={{ textAlign: 'center', position: 'relative', zIndex: 1 }}>
                <h2 style={{ 
                  fontSize: '20px', 
                  fontWeight: '700', 
                  color: '#1e293b', 
                  margin: '0 0 2px 0' 
                }}>
                  Здесь пока пусто
                </h2>
                <p style={{ 
                  fontSize: '16px', 
                  fontWeight: '500', 
                  color: '#64748b', 
                  margin: '0 0 16px 0' 
                }}>
                  {canAdd ? 'Скорее добавляйте свой первый подарок!' : 'В этом вишлисте пока нет подарков'}
                </p>
              </div>
              {canAdd && (
              <Button
                label="Добавить подарок"
                icon="pi pi-plus"
                onClick={() => setShowAddForm(true)}
                className="custom-green-button"
                style={{ fontSize: '16px', padding: '12px 24px', position: 'relative', zIndex: 1 }}
              />
              )}
            </div>
          ) : (
            <>
            <div style={{ marginBottom: '12px' }}>
              <div style={{ position: 'relative', width: '260px' }}>
                <i className="pi pi-sort-alt" style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', fontSize: '16px', color: '#1e293b', pointerEvents: 'none', zIndex: 1 }}></i>
                <select
                  value={itemSort}
                  onChange={e => setItemSort(e.target.value)}
                  style={{ fontSize: '14px', padding: '0 40px 0 40px', borderRadius: '12px', border: '2px solid #18B700', color: '#1e293b', width: '100%', height: '40px', appearance: 'none', WebkitAppearance: 'none', backgroundImage: 'url("/images/path.svg")', backgroundRepeat: 'no-repeat', backgroundPosition: 'right 12px center', backgroundSize: '9px 5px', cursor: 'pointer', outline: 'none', backgroundColor: '#fff', fontFamily: 'inherit' }}
                >
                  <option value="title_asc">По алфавиту (А - Я)</option>
                  <option value="title_desc">По алфавиту (Я - А)</option>
                  <option value="price_asc">По возрастанию цены</option>
                  <option value="price_desc">По убыванию цены</option>
                  <option value="createdAt_desc">По дате добавления</option>
                  <option value="priority_desc">По желанности</option>
                </select>
              </div>
            </div>
            <div className="items-grid">
              {sortItems(items).map(item => (
                <GiftCard
                  key={item.id}
                  item={item}
                  isOwner={isOwner}
                  itemMenuOpen={itemMenuOpen}
                  onImageClick={setSelectedItem}
                  onMenuToggle={(id) => setItemMenuOpen(itemMenuOpen === id ? null : id)}
                  onMenuClose={() => setItemMenuOpen(null)}
                  onEdit={handleEditItem}
                  onTogglePurchased={(item) => { handleTogglePurchased(item); setItemMenuOpen(null); }}
                  onMove={openMoveDialog}
                  onDelete={(id) => { setItemMenuOpen(null); handleDeleteItem(id); }}
                  onReserve={(item) => handleReserve(item, false)}
                  onUnreserve={handleUnreserve}
                />
              ))}
            </div>
            </>
          )}
        </>
      )}

      <ItemDetailDialog
        item={selectedItem}
        visible={!!selectedItem}
        onHide={() => setSelectedItem(null)}
        onDelete={handleDeleteItem}
        isOwner={isOwner}
      />

      <Dialog
        header="Перенести подарок"
        visible={showMoveDialog}
        style={{ width: '400px' }}
        onHide={() => { setShowMoveDialog(false); setMovingItem(null); }}
      >
        {userWishlists.length === 0 ? (
          <p style={{ color: '#64748b' }}>Нет других вишлистов для переноса.</p>
        ) : (
          <div className="flex flex-column gap-2">
            <p style={{ marginBottom: '8px', color: '#64748b' }}>Выберите вишлист:</p>
            {userWishlists.map(w => (
              <button
                key={w.id}
                onClick={() => handleMoveItem(movingItem, w.id)}
                style={{
                  padding: '12px 16px',
                  borderRadius: '8px',
                  border: '2px solid #e2e8f0',
                  background: 'white',
                  textAlign: 'left',
                  cursor: 'pointer',
                  fontSize: '14px',
                  fontWeight: '500',
                  transition: 'border-color 0.2s'
                }}
                onMouseEnter={e => e.currentTarget.style.borderColor = '#188700'}
                onMouseLeave={e => e.currentTarget.style.borderColor = '#e2e8f0'}
              >
                {w.title}
              </button>
            ))}
          </div>
        )}
      </Dialog>
    </div>
  );
}

export default ItemsDialog;
